class ConnectionManager:
    """Manages BLE connections with rate limiting and security."""

    def __init__(self, max_connections=1, connection_timeout_ms=300000):
        self._max_connections = max_connections
        self._connection_timeout_ms = connection_timeout_ms
        self._connections = {}
        self._authenticated = {}
        self._failed_attempts = {}
        self._max_failed_attempts = 5
        self._lockout_duration_ms = 60000
        self._lockout_until = {}
        self._command_timestamps = {}
        self._rate_limit_window_ms = 1000
        self._rate_limit_max_commands = 10

    def add_connection(self, conn_handle):
        if len(self._connections) >= self._max_connections:
            return False
        self._connections[conn_handle] = time.ticks_ms()
        self._authenticated[conn_handle] = False
        self._command_timestamps[conn_handle] = []
        return True

    def remove_connection(self, conn_handle):
        self._connections.pop(conn_handle, None)
        self._authenticated.pop(conn_handle, None)
        self._command_timestamps.pop(conn_handle, None)

    def is_connected(self, conn_handle):
        return conn_handle in self._connections

    def set_authenticated(self, conn_handle, authenticated=True):
        self._authenticated[conn_handle] = authenticated

    def is_authenticated(self, conn_handle):
        return self._authenticated.get(conn_handle, False)

    def check_rate_limit(self, conn_handle):
        """Returns True if the command is allowed, False if rate limited."""
        now = time.ticks_ms()
        if conn_handle not in self._command_timestamps:
            return False

        timestamps = self._command_timestamps[conn_handle]
        # Remove old timestamps outside the window
        self._command_timestamps[conn_handle] = [
            ts for ts in timestamps
            if time.ticks_diff(now, ts) < self._rate_limit_window_ms
        ]
        timestamps = self._command_timestamps[conn_handle]

        if len(timestamps) >= self._rate_limit_max_commands:
            print("Rate limit exceeded for conn_handle:", conn_handle)
            return False

        timestamps.append(now)
        return True

    def record_failed_attempt(self, addr_bytes):
        """Track failed authentication attempts by address."""
        addr_key = bytes(addr_bytes)
        now = time.ticks_ms()

        # Check if currently locked out
        if addr_key in self._lockout_until:
            if time.ticks_diff(now, self._lockout_until[addr_key]) < 0:
                return False  # Still locked out

        count = self._failed_attempts.get(addr_key, 0) + 1
        self._failed_attempts[addr_key] = count

        if count >= self._max_failed_attempts:
            self._lockout_until[addr_key] = time.ticks_add(now, self._lockout_duration_ms)
            self._failed_attempts[addr_key] = 0
            print("Address locked out due to too many failed attempts")
            return False
        return True

    def is_locked_out(self, addr_bytes):
        addr_key = bytes(addr_bytes)
        if addr_key in self._lockout_until:
            now = time.ticks_ms()
            if time.ticks_diff(now, self._lockout_until[addr_key]) < 0:
                return True
            else:
                del self._lockout_until[addr_key]
        return False

    def check_connection_timeout(self):
        """Check and disconnect timed-out connections."""
        now = time.ticks_ms()
        timed_out = []
        for conn_handle, connect_time in self._connections.items():
            if time.ticks_diff(now, connect_time) > self._connection_timeout_ms:
                timed_out.append(conn_handle)
        return timed_out

    def get_connection_count(self):
        return len(self._connections)


class InputValidator:
    """Validates and sanitizes BLE input data."""

    # Allowed commands whitelist
    VALID_COMMANDS = {
        0x01: "LED_ON",
        0x02: "LED_OFF",
        0x03: "RELAY_ON",
        0x04: "RELAY_OFF",
        0x05: "READ_SENSORS",
        0x06: "RESET",
        0x07: "GET_STATUS",
        0x10: "SET_CONFIG",
    }

    MAX_PAYLOAD_SIZE = 128

    @staticmethod
    def validate_command(data):
        """Validate command byte data. Returns (is_valid, command_id, payload)."""
        if not data or len(data) < 1:
            return False, None, None

        if len(data) > InputValidator.MAX_PAYLOAD_SIZE:
            print("Payload too large:", len(data))
            return False, None, None

        command_id = data[0]
        if command_id not in InputValidator.VALID_COMMANDS:
            print("Invalid command ID:", command_id)
            return False, None, None

        payload = data[1:] if len(data) > 1 else b""
        return True, command_id, payload

    @staticmethod
    def validate_led_value(data):
        """Validate LED control value (0 or 1, or RGB values)."""
        if not data or len(data) < 1:
            return False, None

        if len(data) > 4:
            return False, None

        if len(data) == 1:
            val = data[0]
            if val not in (0, 1):
                return False, None
            return True, val

        # RGB: 3 bytes
        if len(data) == 3:
            return True, tuple(data)

        return False, None

    @staticmethod
    def validate_relay_value(data):
        """Validate relay control value (0 or 1)."""
        if not data or len(data) != 1:
            return False, None
        val = data[0]
        if val not in (0, 1):
            return False, None
        return True, val

    @staticmethod
    def validate_config(data):
        """Validate configuration JSON data."""
        if not data or len(data) > InputValidator.MAX_PAYLOAD_SIZE:
            return False, None

        try:
            # Decode and parse JSON
            config_str = data.decode("utf-8")
            config = json.loads(config_str)

            if not isinstance(config, dict):
                return False, None

            # Whitelist allowed config keys and validate types
            allowed_keys = {
                "interval": int,
                "threshold": (int, float),
                "name": str,
                "enabled": bool,
            }

            sanitized = {}
            for key, value in config.items():
                if key not in allowed_keys:
                    print("Unknown config key:", key)
                    continue

                expected_type = allowed_keys[key]
                if not isinstance(value, expected_type):
                    print("Invalid type for key:", key)
                    return False, None

                # Additional range checks
                if key == "interval" and not (100 <= value <= 3600000):
                    return False, None
                if key == "threshold" and not (-50 <= value <= 150):
                    return False, None
                if key == "name" and (len(value) > 32 or not value.isalnum()):
                    return False, None

                sanitized[key] = value

            return True, sanitized

        except (ValueError, UnicodeError) as e:
            print("Config parse error:", e)
            return False, None


class SensorReader:
    """Reads sensor data from hardware with caching."""

    def __init__(self, temp_pin=36, humidity_pin=39, battery_pin=34):
        self._temp_adc = machine.ADC(machine.Pin(temp_pin))
        self._temp_adc.atten(machine.ADC.ATTN_11DB)
        self._temp_adc.width(machine.ADC.WIDTH_12BIT)

        self._humidity_adc = machine.ADC(machine.Pin(humidity_pin))
        self._humidity_adc.atten(machine.ADC.ATTN_11DB)
        self._humidity_adc.width(machine.ADC.WIDTH_12BIT)

        self._battery_adc = machine.ADC(machine.Pin(battery_pin))
        self._battery_adc.atten(machine.ADC.ATTN_11DB)
        self._battery_adc.width(machine.ADC.WIDTH_12BIT)

        self._cache = {}
        self._cache_duration_ms = 2000
        self._cache_timestamps = {}

    def _read_cached(self, key, read_func):
        now = time.ticks_ms()
        if key in self._cache_timestamps:
            if time.ticks_diff(now, self._cache_timestamps[key]) < self._cache_duration_ms:
                return self._cache[key]

        value = read_func()
        self._cache[key] = value
        self._cache_timestamps[key] = now
        return value

    def read_temperature(self):
        """Read temperature in Celsius * 100 (as integer for BLE)."""
        def _read():
            raw = self._temp_adc.read()
            # Convert ADC to voltage (3.3V reference, 12-bit)
            voltage = raw * 3.3 / 4095
            # Example: LM35 sensor (10mV per degree C)
            temp_c = voltage * 100
            return int(temp_c * 100)  # Return as centidegrees
        return self._read_cached("temperature", _read)

    def read_humidity(self):
        """Read humidity percentage * 100."""
        def _read():
            raw = self._humidity_adc.read()
            voltage = raw * 3.3 / 4095
            # Example conversion for analog humidity sensor
            humidity = (voltage / 3.3) * 100
            return int(humidity * 100)
        return self._read_cached("humidity", _read)

    def read_battery(self):
        """Read battery level as percentage."""
        def _read():
            raw = self._battery_adc.read()
            voltage = raw * 3.3 / 4095
            # Assuming voltage divider: actual voltage = reading * 2
            actual_voltage = voltage * 2
            # Map 3.0V-4.2V to 0-100%
            percentage = max(0, min(100, int((actual_voltage - 3.0) / 1.2 * 100)))
            return percentage
        return self._read_cached("battery", _read)

    def read_all(self):
        """Read all sensors and return as packed bytes."""
        temp = self.read_temperature()
        humidity = self.read_humidity()
        battery = self.read_battery()
        # Pack: temp (int16), humidity (uint16), battery (uint8)
        return struct.pack("<hHB", temp, humidity, battery)


class DeviceController:
    """Controls device hardware outputs."""

    def __init__(self, led_pin=2, relay_pin=15):
        self._led = machine.Pin(led_pin, machine.Pin.OUT)
        self._relay = machine.Pin(relay_pin, machine.Pin.OUT)
        self._led.value(0)
        self._relay.value(0)
        self._config = {
            "interval": 5000,
            "threshold": 3000,
            "name": "ESP32Device",
            "enabled": True,
        }

    def set_led(self, value):
        if isinstance(value, int):
            self._led.value(value)
        return self._led.value()

    def set_relay(self, value):
        self._relay.value(value)
        return self._relay.value()

    def get_status(self):
        """Return device status as bytes."""
        status = {
            "led": self._led.value(),
            "relay": self._relay.value(),
            "uptime": time.ticks_ms(),
            "config": self._config,
        }
        return json.dumps(status).encode("utf-8")

    def update_config(self, config_dict):
        for key, value in config_dict.items():
            if key in self._config:
                self._config[key] = value
        return True

    def reset(self):
        self._led.value(0)
        self._relay.value(0)


class BLEDeviceServer:
    """Main BLE GATT server for IoT device control."""

    def __init__(self, device_name="ESP32-IoT"):
        self._device_name = device_name
        self._ble = ubluetooth.BLE()
        self._ble.active(True)

        self._conn_mgr = ConnectionManager(max_connections=2)
        self._validator = InputValidator()
        self._sensors = SensorReader()
        self._controller = DeviceController()

        # Generate a static passkey (in production, use device-specific key)
        self._passkey = 123456  # 6-digit numeric passkey

        self._configure_security()
        self._register_services()
        self._start_advertising()

        self._notify_connections = set()
        self._last_notify_time = 0
        self._notify_interval_ms = 5000

        print("BLE Device Server initialized:", device_name)
        print("Passkey for pairing:", self._passkey)

    def _configure_security(self):
        """Configure BLE security with bonding and MITM protection."""
        self._ble.irq(self._irq_handler)

        # Configure security parameters
        # io_capability: DISPLAY_ONLY=0, DISPLAY_YESNO=1, KEYBOARD_ONLY=2,
        #                NO_INPUT_NO_OUTPUT=3, KEYBOARD_DISPLAY=4
        # For passkey display on device (mobile enters passkey):
        self._ble.config(
            bond=True,
            mitm=True,
            le_secure=True,
            io=0,  # DISPLAY_ONLY - device displays passkey, mobile enters it
        )

        # Set GAP device name
        self._ble.config(gap_name=self._device_name)

    def _register_services(self):
        """Register all GATT services and characteristics."""

        # Device Information Service (standard BLE SIG service)
        device_info_service = (
            _DEVICE_INFO_SERVICE_UUID,
            (
                (_MANUFACTURER_NAME_UUID, _FLAG_READ),
                (_MODEL_NUMBER_UUID, _FLAG_READ),
                (_FIRMWARE_REV_UUID, _FLAG_READ),
            ),
        )

        # Sensor Service - read-only sensor data with encrypted read
        sensor_service = (
            _SENSOR_SERVICE_UUID,
            (
                # Temperature: encrypted read + notify
                (_TEMPERATURE_UUID, _FLAG_READ_ENCRYPTED | _FLAG_NOTIFY),
                # Humidity: encrypted read + notify
                (_HUMIDITY_UUID, _FLAG_READ_ENCRYPTED | _FLAG_NOTIFY),
                # Battery: encrypted read + notify
                (_BATTERY_UUID, _FLAG_READ_ENCRYPTED | _FLAG_NOTIFY),
                # Sensor bundle (all sensors packed): encrypted read + notify
                (_SENSOR_BUNDLE_UUID, _FLAG_READ_ENCRYPTED | _FLAG_NOTIFY),
            ),
        )

        # Control Service - write commands with encrypted write
        control_service = (
            _CONTROL_SERVICE_UUID,
            (
                # Command endpoint: encrypted write
                (_COMMAND_UUID, _FLAG_WRITE_ENCRYPTED),
                # LED control: encrypted read + write
                (_LED_CONTROL_UUID, _FLAG_READ_ENCRYPTED | _FLAG_WRITE_ENCRYPTED),
                # Relay control: encrypted read + write
                (_RELAY_CONTROL_UUID, _FLAG_READ_ENCRYPTED | _FLAG_WRITE_ENCRYPTED),
                # Configuration: encrypted read + write
                (_CONFIG_UUID, _FLAG_READ_ENCRYPTED | _FLAG_WRITE_ENCRYPTED),
                # Status: encrypted read + notify
                (_STATUS_UUID, _FLAG_READ_ENCRYPTED | _FLAG_NOTIFY),
            ),
        )

        # Register all services
        handles = self._ble.gatts_register_services([
            device_info_service,
            sensor_service,
            control_service,
        ])

        # Store characteristic handles
        # Device Info handles
        (
            self._h_manufacturer,
            self._h_model,
            self._h_firmware,
        ) = handles[0]

        # Sensor handles
        (
            self._h_temperature,
            self._h_humidity,
            self._h_battery,
            self._h_sensor_bundle,
        ) = handles[1]

        # Control handles
        (
            self._h_command,
            self._h_led,
            self._h_relay,
            self._h_config,
            self._h_status,
        ) = handles[2]

        # Set initial values for device info
        self._ble.gatts_write(self._h_manufacturer, b"IoT Corp")
        self._ble.gatts_write(self._h_model, b"ESP32-CTL-v1")
        self._ble.gatts_write(self._h_firmware, b"1.0.0")

        # Set initial sensor values
        self._update_sensor_values()

        # Set initial control values
        self._ble.gatts_write(self._h_led, struct.pack("<B", 0))
        self._ble.gatts_write(self._h_relay, struct.pack("<B", 0))
        self._ble.gatts_write(self._h_config, json.dumps(self._controller._config).encode("utf-8"))
        self._ble.gatts_write(self._h_status, self._controller.get_status())

    def _start_advertising(self):
        """Start BLE advertising with appropriate flags."""
        # Build advertising payload
        adv_data = self._build_adv_payload(
            name=self._device_name,
            services=[_SENSOR_SERVICE_UUID, _CONTROL_SERVICE_UUID],
            appearance=0x0540,  # Generic Sensor
        )

        # Scan response with full name
        resp_data = self._build_adv_payload(
            name=self._device_name,
        )

        # Advertise with limited discoverable mode for better security
        self._ble.gap_advertise(
            100000,  # Interval in microseconds (100ms)
            adv_data=adv_data,
            resp_data=resp_data,
            connectable=True,
        )
        print("Advertising started")

    def _build_adv_payload(self, name=None, services=None, appearance=None):
        """Build BLE advertising payload."""
        payload = bytearray()

        # Flags: General Discoverable + BR/EDR Not Supported
        payload += struct.pack("BBB", 2, 0x01, 0x06)

        if name:
            name_bytes = name.encode("utf-8")[:20]  # Limit name length
            payload += struct.pack("BB", len(name_bytes) + 1, 0x09)
            payload += name_bytes

        if appearance is not None:
            payload += struct.pack("<BBH", 3, 0x19, appearance)

        if services:
            for uuid in services:
                uuid_bytes = bytes(uuid)
                if len(uuid_bytes) == 2:
                    payload += struct.pack("BB", len(uuid_bytes) + 1, 0x03)
                else:
                    payload += struct.pack("BB", len(uuid_bytes) + 1, 0x07)
                payload += uuid_bytes

        return bytes(payload)

    def _irq_handler(self, event, data):
        """Handle BLE IRQ events."""

        if event == _IRQ_CENTRAL_CONNECT:
            conn_handle, addr_type, addr = data
            print("Connected:", conn_handle, "addr:", bytes(addr).hex())

            # Check lockout
            if self._conn_mgr.is_locked_out(addr):
                print("Address is locked out, disconnecting")
                self._ble.gap_disconnect(conn_handle)
                return

            if not self._conn_mgr.add_connection(conn_handle):
                print("Max connections reached, disconnecting")
                self._ble.gap_disconnect(conn_handle)
                return

            # Continue advertising for additional connections if allowed
            if self._conn_mgr.get_connection_count() < 2:
                self._start_advertising()

        elif event == _IRQ_CENTRAL_DISCONNECT:
            conn_handle, addr_type, addr = data
            print("Disconnected:", conn_handle)
            self._conn_mgr.remove_connection(conn_handle)
            self._notify_connections.discard(conn_handle)
            # Restart advertising
            self._start_advertising()

        elif event == _IRQ_GATTS_WRITE:
            conn_handle, attr_handle = data
            self._handle_write(conn_handle, attr_handle)

        elif event == _IRQ_GATTS_READ_REQUEST:
            conn_handle, attr_handle = data
            self._handle_read(conn_handle, attr_handle)

        elif event == _IRQ_ENCRYPTION_UPDATE:
            conn_handle, encrypted, authenticated, bonded, key_size = data
            print(
                "Encryption update: conn=%d enc=%d auth=%d bond=%d key_size=%d"
                % (conn_handle, encrypted, authenticated, bonded, key_size)
            )
            if encrypted and authenticated:
                self._conn_mgr.set_authenticated(conn_handle, True)
                self._notify_connections.add(conn_handle)
                print("Connection authenticated and encrypted")
            elif encrypted and not authenticated:
                # Encrypted but not authenticated (no MITM protection)
                # Still allow but log warning
                print("WARNING: Encrypted but not authenticated (no MITM)")
                self._conn_mgr.set_authenticated(conn_handle, True)
                self._notify_connections.add(conn_handle)

        elif event == _IRQ_PASSKEY_ACTION:
            conn_handle, action, passkey = data
            print("Passkey action:", action)
            if action == _PASSKEY_ACTION_DISPLAY:
                # Display passkey for user to enter on mobile
                print("Display passkey:", self._passkey)
                self._ble.gap_passkey(conn_handle, _PASSKEY_ACTION_DISPLAY, self._passkey)

    def _handle_write(self, conn_handle, attr_handle):
        """Handle write requests with validation."""

        if not self._conn_mgr.is_connected(conn_handle):
            print("Write from unknown connection")
            return

        # Rate limiting
        if not self._conn_mgr.check_rate_limit(conn_handle):
            print("Rate limited, ignoring write")
            return

        # Read the written data
        data = self._ble.gatts_read(attr_handle)

        if attr_handle == self._h_command:
            self._handle_command(conn_handle, data)

        elif attr_handle == self._h_led:
            valid, value = self._validator.validate_led_value(data)
            if valid:
                result = self._controller.set_led(value)
                self._ble.gatts_write(self._h_led, struct.pack("<B", result))
                print("LED set to:", value)
                self._notify_status_change()
            else:
                print("Invalid LED value")

        elif attr_handle == self._h_relay:
            valid, value = self._validator.validate_relay_value(data)
            if valid:
                result = self._controller.set_relay(value)
                self._ble.gatts_write(self._h_relay, struct.pack("<B", result))
                print("Relay set to:", value)
                self._notify_status_change()
            else:
                print("Invalid relay value")

        elif attr_handle == self._h_config:
            valid, config = self._validator.validate_config(data)
            if valid:
                self._controller.update_config(config)
                # Write back sanitized config
                config_bytes = json.dumps(self._controller._config).encode("utf-8")
                self._ble.gatts_write(self._h_config, config_bytes)
                print("Config updated:", config)
                self._notify_status_change()
            else:
                print("Invalid config data")

        else:
            print("Write to unknown handle:", attr_handle)

    def _handle_command(self, conn_handle, data):
        """Process validated commands."""
        valid, command_id, payload = self._validator.validate_command(data)
        if not valid:
            print("Invalid command received")
            return

        command_name = self._validator.VALID_COMMANDS[command_id]
        print("Command:", command_name)

        if command_id == 0x01:  # LED_ON
            self._controller.set_led(1)
            self._ble.gatts_write(self._h_led, struct.pack("<B", 1))

        elif command_id == 0x02:  # LED_OFF
            self._controller.set_led(0)
            self._ble.gatts_write(self._h_led, struct.pack("<B", 0))

        elif command_id == 0x03:  # RELAY_ON
            self._controller.set_relay(1)
            self._ble.gatts_write(self._h_relay, struct.pack("<B", 1))

        elif command_id == 0x04:  # RELAY_OFF
            self._controller.set_relay(0)
            self._ble.gatts_write(self._h_relay, struct.pack("<B", 0))

        elif command_id == 0x05:  # READ_SENSORS
            self._update_sensor_values()
            self._send_sensor_notifications()

        elif command_id == 0x06:  # RESET
            self._controller.reset()
            self._ble.gatts_write(self._h_led, struct.pack("<B", 0))
            self._ble.gatts_write(self._h_relay, struct.pack("<B", 0))

        elif command_id == 0x07:  # GET_STATUS
            status = self._controller.get_status()
            self._ble.gatts_write(self._h_status, status)
            for ch in self._notify_connections:
                try:
                    self._ble.gatts_notify(ch, self._h_status, status)
                except Exception:
                    pass

        elif command_id == 0x10:  # SET_CONFIG
            if payload:
                valid, config = self._validator.validate_config(payload)
                if valid:
                    self._controller.update_config(config)

        self._notify_status_change()

    def _handle_read(self, conn_handle, attr_handle):
        """Handle read requests - update values before read."""
        # Update sensor values on read
        sensor_handles = (
            self._h_temperature,
            self._h_humidity,
            self._h_battery,
            self._h_sensor_bundle,
        )
        if attr_handle in sensor_handles:
            self._update_sensor_values()

        elif attr_handle == self._h_status:
            self._ble.gatts_write(self._h_status, self._controller.get_status())

    def _update_sensor_values(self):
        """Update all sensor characteristic values."""
        temp = self._sensors.read_temperature()
        humidity = self._sensors.read_humidity()
        battery = self._sensors.read_battery()

        self._ble.gatts_write(self._h_temperature, struct.pack("<h", temp))
        self._ble.gatts_write(self._h_humidity, struct.pack("<H", humidity))
        self._ble.gatts_write(self._h_battery, struct.pack("<B", battery))
        self._ble.gatts_write(self._h_sensor_bundle, self._sensors.read_all())

    def _send_sensor_notifications(self):
        """Send sensor data notifications to subscribed connections."""
        temp = struct.pack("<h", self._sensors.read_temperature())
        humidity = struct.pack("<H", self._sensors.read_humidity())
        battery = struct.pack("<B", self._sensors.read_battery())
        bundle = self._sensors.read_all()

        for conn_handle in list(self._notify_connections):
            try:
                self._ble.gatts_notify(conn_handle, self._h_temperature, temp)
                self._ble.gatts_notify(conn_handle, self._h_humidity, humidity)
                self._ble.gatts_notify(conn_handle, self._h_battery, battery)
                self._ble.gatts_notify(conn_handle, self._h_sensor_bundle, bundle)
            except Exception as e:
                print("Notify error:", e)
                self._notify_connections.discard(conn_handle)

    def _notify_status_change(self):
        """Notify connected clients of status change."""
        status = self._controller.get_status()
        self._ble.gatts_write(self._h_status, status)
        for conn_handle in list(self._notify_connections):
            try:
                self._ble.gatts_notify(conn_handle, self._h_status, status)
            except Exception:
                self._notify_connections.discard(conn_handle)

    def update(self):
        """Main loop update - call periodically."""
        now = time.ticks_ms()

        # Check connection timeouts
        timed_out = self._conn_mgr.check_connection_timeout()
        for conn_handle in timed_out:
            print("Connection timed out:", conn_handle)
            try:
                self._ble.gap_disconnect(conn_handle)
            except Exception:
                pass
            self._conn_mgr.remove_connection(conn_handle)
            self._notify_connections.discard(conn_handle)

        # Periodic sensor notifications
        if time.ticks_diff(now, self._last_notify_time) >= self._notify_interval_ms:
            self._last_notify_time = now
            if self._notify_connections:
                self._update_sensor_values()
                self._send_sensor_notifications()

    def stop(self):
        """Stop the BLE server."""
        # Disconnect all clients
        for conn_handle in list(self._conn_mgr._connections.keys()):
            try:
                self._ble.gap_disconnect(conn_handle)
            except Exception:
                pass

        self._ble.active(False)
        print("BLE Server stopped")


def main():
    """Main entry point."""
    print("Starting ESP32 BLE IoT Device Server...")
    print("=" * 50)

    server = BLEDeviceServer(device_name="ESP32-IoT-001")

    print("Server running. Waiting for connections...")
    print("Pair using the displayed passkey on your mobile app.")
    print("=" * 50)

    try:
        while True:
            server.update()
            time.sleep_ms(100)
    except KeyboardInterrupt:
        print("\nShutting down...")
        server.stop()
        print("Goodbye!")


if __name__ == "__main__":
    main()